import{_ as g,y as a,a as c,o as r,ag as h,D as o,g as i,I as l}from"./chunks/framework.RVu0gECZ.js";const T=JSON.parse('{"title":"Quản lý hoa hồng","description":"","frontmatter":{},"headers":[],"relativePath":"multi-vendor-marketplace/commission-management.md","filePath":"multi-vendor-marketplace/commission-management.md","lastUpdated":1775325172000}'),s={name:"multi-vendor-marketplace/commission-management.md"};function p(e,n,u,m,b,d){const t=a("ImagePopup");return r(),c("div",null,[n[0]||(n[0]=h('<h1 id="quan-ly-hoa-hong" tabindex="-1">Quản lý hoa hồng <a class="header-anchor" href="#quan-ly-hoa-hong" aria-label="Permalink to &quot;Quản lý hoa hồng&quot;">​</a></h1><p>Hệ thống Quản lý hoa hồng Marketplace tại VNS cho phép chủ sở hữu nền tảng (quản trị viên) thiết lập và quản lý tỷ lệ hoa hồng cho người bán một cách linh hoạt và rõ ràng.</p><p>Hệ thống này giúp thị trường kiếm được thu nhập ổn định và cũng mang lại cho quản trị viên khả năng đưa ra tỷ lệ hoa hồng đặc biệt cho người bán dưới dạng phần thưởng hoặc ưu đãi khi cần thiết.</p><p>Có ba phần chính để xử lý hoa hồng:</p><p><strong>1) Tỷ lệ phần trăm hoa hồng quản trị (Tỷ lệ toàn cầu)</strong></p><p><strong>2) Hoa hồng người bán (Tỷ lệ tùy chỉnh)</strong></p><p><strong>3) Báo cáo bán hàng minh bạch</strong></p><h3 id="phan-tram-hoa-hong-quan-tri-ty-le-toan-cau" tabindex="-1">Phần trăm hoa hồng quản trị (Tỷ lệ toàn cầu) <a class="header-anchor" href="#phan-tram-hoa-hong-quan-tri-ty-le-toan-cau" aria-label="Permalink to &quot;Phần trăm hoa hồng quản trị (Tỷ lệ toàn cầu)&quot;">​</a></h3><p>Tỷ lệ hoa hồng toàn cầu là tỷ lệ phần trăm tiêu chuẩn tự động áp dụng cho tất cả người bán.</p><p>Đây là cách dễ dàng và đáng tin cậy nhất để kiếm tiền từ việc bán hàng vì mọi người bán trên nền tảng đều trả mức giá như nhau.</p><p><strong>Tại sao nó quan trọng:</strong></p><ol><li>Đảm bảo rằng tất cả người bán đều được đối xử công bằng và bình đẳng.</li><li>Xử lý đơn giản — không cần thiết lập các khoản hoa hồng riêng trừ khi cần thiết.</li><li>Hỗ trợ duy trì thu nhập ổn định cho thị trường.</li></ol><p><strong>Các bước để thiết lập hoa hồng toàn cầu</strong></p><ol><li>Trong Bảng quản trị, đi tới <strong>Cấu hình → Thị trường → Chung</strong>.</li><li>Xác định vị trí trường <strong>Tỷ lệ hoa hồng quản trị</strong>.</li><li>Nhập tỷ lệ phần trăm bạn muốn áp dụng trên toàn cầu.</li><li>Nhấp vào <strong>Lưu cấu hình</strong> — giá bây giờ sẽ được áp dụng tự động cho tất cả người bán.</li></ol>',14)),o(t,{src:"/images/multi-vendor-marketplace/configure_commission.png",alt:"Global Commission Configuration"}),n[1]||(n[1]=h('<p><strong>Ví dụ:</strong><br> Nếu tỷ giá toàn cầu là 10% và người bán bán thứ gì đó với giá 1.000 USD thì quản trị viên sẽ tự động nhận được 100 USD làm hoa hồng, trong khi người bán giữ lại 900 USD.</p><hr><h3 id="shoa-hong-nguoi-ban-ty-le-tuy-chinh" tabindex="-1">SHoa hồng người bán (Tỷ lệ tùy chỉnh) <a class="header-anchor" href="#shoa-hong-nguoi-ban-ty-le-tuy-chinh" aria-label="Permalink to &quot;SHoa hồng người bán (Tỷ lệ tùy chỉnh)&quot;">​</a></h3><p>Đôi khi, bạn có thể muốn thiết lập tỷ lệ hoa hồng duy nhất cho người bán cụ thể.</p><p>Đây được gọi là tỷ lệ hoa hồng tùy chỉnh và có thể cao hơn hoặc thấp hơn tỷ lệ chung, tùy theo thỏa thuận.</p><p><strong>Khi nào nên sử dụng hoa hồng tùy chỉnh:</strong></p><ol><li>Để thúc đẩy người bán mới bằng cách cung cấp cho họ mức hoa hồng thấp hơn.</li><li>Là phần thưởng dành cho những người bán hàng thực hiện tốt.</li><li>Đối với các giao dịch hợp tác độc đáo.</li><li>Dành cho các chương trình khuyến mãi ngắn hạn hoặc tăng giá trong thời gian bán hàng theo mùa.</li></ol><p><strong>Tính năng chính:</strong></p><ol><li>Chuyển đổi trạng thái có thể bật hoặc tắt hoa hồng tùy chỉnh bất cứ lúc nào.</li><li>Khi tính năng này được bật, hoa hồng tùy chỉnh sẽ thay thế hoa hồng toàn cầu cho người bán cụ thể đó.</li><li>Khi bị tắt, người bán sẽ quay lại tỷ giá toàn cầu.</li></ol><p><strong>Cách đặt hoa hồng tùy chỉnh cho người bán:</strong></p><ol><li>Trong Bảng quản trị, đi tới: <strong>Thị trường → Người bán</strong>.</li><li>Tìm người bán bạn muốn chỉnh sửa và nhấp vào biểu tượng <strong>Chỉnh sửa</strong>.</li><li>Xác định vị trí phần <strong>Hoa hồng người bán</strong>.</li><li>Nhập tốc độ mong muốn và sử dụng <strong>Chuyển đổi trạng thái</strong> để BẬT.</li><li>Lưu cài đặt - tỷ giá tùy chỉnh hiện sẽ chỉ áp dụng cho người bán đó.</li></ol>',11)),o(t,{src:"/images/multi-vendor-marketplace/seller_commission.png",alt:"Seller Custom Commission"}),n[2]||(n[2]=h('<p><strong>Ví dụ:</strong><br> Nếu thuế suất toàn cầu là 10% nhưng Người bán A được hưởng thuế suất tùy chỉnh là 5% thì chỉ 5% sẽ được khấu trừ vào doanh thu của Người bán A, trong khi những người khác tiếp tục bị tính phí 10%.</p><hr><h3 id="sbao-cao-ban-hang-minh-bach" tabindex="-1">SBáo cáo bán hàng minh bạch <a class="header-anchor" href="#sbao-cao-ban-hang-minh-bach" aria-label="Permalink to &quot;SBáo cáo bán hàng minh bạch&quot;">​</a></h3><p>VNS có tích hợp sẵn công cụ báo cáo bán hàng cho phép người bán dễ dàng theo dõi số tiền hoa hồng họ đã trả theo thời gian.</p><p>Sự cởi mở này giúp tạo niềm tin giữa thị trường và người bán bằng cách đảm bảo không có khoản phí bí mật nào.</p><p><strong>Lợi ích của việc báo cáo bán hàng:</strong></p><ol><li>Người bán có thể theo dõi tổng số tiền hoa hồng họ trả cho quản trị viên.</li><li>Cung cấp thông tin chi tiết về cách hoa hồng tác động đến lợi nhuận tổng thể.</li><li>Khuyến khích các mối quan hệ kinh doanh lành mạnh.</li></ol><p><strong>Người bán có thể tìm thấy báo cáo này ở đâu:</strong></p><ol><li>Từ <strong>Bảng điều khiển người bán</strong>, điều hướng đến: <strong>Báo cáo → Tổng số tiền hoa hồng đã trả</strong>.</li></ol>',9)),o(t,{src:"/images/multi-vendor-marketplace/total_commission_paid_reporting.png",alt:"Total Commission Paid Reporting"}),n[3]||(n[3]=i("p",null,[i("strong",null,"Ví dụ:"),i("br"),l(" Người bán bán hàng hóa trị giá 50.000 USD với tỷ lệ hoa hồng 10% sẽ thấy 5.000 USD được liệt kê trong phần “Tổng số tiền hoa hồng đã trả”.")],-1))])}const y=g(s,[["render",p]]);export{T as __pageData,y as default};
